import androidx.lifecycle.ViewModelProvider
import com.court.assistant.ui.Navigation
import com.court.assistant.ui.theme.CourtAssistantTheme
import com.court.assistant.viewmodel.MainViewModel

class MainActivity : ComponentActivity() {
    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestMultiplePermissions()
    ) { permissions ->
        // 检查所有权限是否已授予
        val allGranted = permissions.all { it.value }
        if (allGranted) {
            // 权限已授予，安全加载短信
            getViewModel()?.loadSms()
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        requestPermissions()

        setContent {
            CourtAssistantTheme {
                Surface(modifier = Modifier.fillMaxSize()) {
                    Navigation(viewModel = getViewModel()!!)
                }
            }
        }
    }

    private fun getViewModel(): MainViewModel? {
        try {
            return ViewModelProvider(this)[MainViewModel::class.java]
        } catch (e: Exception) {
            android.util.Log.e("MainActivity", "Failed to create ViewModel", e)
            return null
        }
    }

    private fun requestPermissions() {
        val basePermissions = arrayOf(
            Manifest.permission.READ_SMS,
            Manifest.permission.RECEIVE_SMS,
            Manifest.permission.READ_CALENDAR,
            Manifest.permission.WRITE_CALENDAR
        )

        // Android 13+ 需要通知权限
        val needed = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            basePermissions + Manifest.permission.POST_NOTIFICATIONS
        } else {
            basePermissions
        }

        val toRequest = needed.filter {
            ContextCompat.checkSelfPermission(this, it) != PackageManager.PERMISSION_GRANTED
        }.toTypedArray()

        if (toRequest.isEmpty()) {
            // 所有权限已授予
            getViewModel()?.loadSms()
        } else {
            permissionLauncher.launch(toRequest)
        }
    }
}

package com.court.assistant.sms

import android.content.Context
import android.net.Uri
import android.provider.Telephony

data class RawSms(
    val sender: String,
    val body: String,
    val date: Long
)

class SmsReader(private val context: Context) {
    private val courtKeywords = listOf("法院", "开庭", "传票", "案件", "送达", "court.gov.cn", "案号")

    fun readCourtSms(): List<RawSms> {
        val smsList = mutableListOf<RawSms>()
        val uri = Telephony.Sms.CONTENT_URI
        val projection = arrayOf(
            Telephony.Sms.ADDRESS,
            Telephony.Sms.BODY,
            Telephony.Sms.DATE
        )
        val cursor = context.contentResolver.query(
            uri, projection, null, null,
            "${Telephony.Sms.DATE} DESC"
        ) ?: return emptyList()

        cursor.use {
            val addrIdx = it.getColumnIndexOrThrow(Telephony.Sms.ADDRESS)
            val bodyIdx = it.getColumnIndexOrThrow(Telephony.Sms.BODY)
            val dateIdx = it.getColumnIndexOrThrow(Telephony.Sms.DATE)
            while (it.moveToNext()) {
                val body = it.getString(bodyIdx) ?: continue
                if (courtKeywords.any { kw -> body.contains(kw) }) {
                    smsList.add(RawSms(
                        sender = it.getString(addrIdx) ?: "",
                        body = body,
                        date = it.getLong(dateIdx)
                    ))
                }
            }
        }
        return smsList
    }
}

package com.court.assistant.sms

import java.text.SimpleDateFormat
import java.util.*

data class ParsedSms(
    val caseNumber: String?,
    val courtName: String?,
    val hearingTime: Long?,
    val partyNames: String?,
    val webUrl: String?
)

class SmsParser {
    // 案号: （2024）鲁1312民初1324号
    private val caseNumberPattern = Regex("[（(]\\d{4}[）)][^\\s，。,\\.]+号")
    // 法院名称: 【xxx法院】
    private val courtPattern = Regex("【(.+?法院[）】]?)")
    // 当事人: 】xxx你好 or 】xxx，你好
    private val partyPattern = Regex("】(\\S+?)(?:你好|，你好|,你好)")
    // URL
    private val urlPattern = Regex("https?://[^\\s<>\"]+")
    // 开庭时间 - 多种格式
    private val datePatterns = listOf(
        Regex("(\\d{4})年(\\d{1,2})月(\\d{1,2})日[\\s]*(\\d{1,2})[时点:：](\\d{0,2})"),
        Regex("(\\d{4})-(\\d{1,2})-(\\d{1,2})\\s+(\\d{1,2}):(\\d{2})"),
        Regex("(\\d{4})/(\\d{1,2})/(\\d{1,2})\\s+(\\d{1,2}):(\\d{2})")
    )

    fun parse(body: String): ParsedSms {
        val caseNumber = caseNumberPattern.find(body)?.value
        val courtFull = courtPattern.find(body)?.groupValues?.getOrNull(1)
        val courtName = courtFull?.let { simplifyCourtName(it) }
        val partyNames = partyPattern.find(body)?.groupValues?.getOrNull(1)
        val webUrl = urlPattern.find(body)?.value
        val hearingTime = parseHearingTime(body)

        return ParsedSms(
            caseNumber = caseNumber,
            courtName = courtName,
            hearingTime = hearingTime,
            partyNames = partyNames,
            webUrl = webUrl
        )
    }

    private fun simplifyCourtName(name: String): String {
        // 去掉省市前缀，保留区+法院
        // "临沂市河东区人民法院" -> "河东区法院"
        val cleaned = name.replace("】", "").replace("【", "")
        val match = Regex("(\\S+?[区县市旗])人民法院").find(cleaned)
        if (match != null) {
            val district = match.groupValues[1]
            // 取最后一个行政区划
            val parts = Regex("[省市州盟]").split(district)
            return "${parts.last()}法院"
        }
        return cleaned.replace("人民", "")
    }

    private fun parseHearingTime(text: String): Long? {
        for (pattern in datePatterns) {
            val match = pattern.find(text) ?: continue
            try {
                val year = match.groupValues[1].toInt()
                val month = match.groupValues[2].toInt()
                val day = match.groupValues[3].toInt()
                val hour = match.groupValues[4].toInt()
                val minute = match.groupValues.getOrNull(5)?.takeIf { it.isNotEmpty() }?.toInt() ?: 0
                val cal = Calendar.getInstance().apply {
                    set(year, month - 1, day, hour, minute, 0)
                    set(Calendar.MILLISECOND, 0)
                }
                return cal.timeInMillis
            } catch (_: Exception) { continue }
        }
        return null
    }
}

package com.court.assistant.ui

import androidx.compose.runtime.Composable
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import androidx.navigation.navArgument
import com.court.assistant.viewmodel.MainViewModel

@Composable
fun Navigation(viewModel: MainViewModel) {
    val navController = rememberNavController()

    NavHost(navController = navController, startDestination = "main") {
        composable("main") {
            MainScreen(
                viewModel = viewModel,
                onOpenWebView = { smsId, url ->
                    navController.navigate("webview/$smsId/${java.net.URLEncoder.encode(url, "UTF-8")}")
                },
                onOpenPdf = { pdfId ->
                    navController.navigate("pdf/$pdfId")
                }
            )
        }
        composable(
            "webview/{smsId}/{url}",
            arguments = listOf(
                navArgument("smsId") { type = NavType.LongType },
                navArgument("url") { type = NavType.StringType }
            )
        ) { entry ->
            val smsId = entry.arguments?.getLong("smsId") ?: return@composable
            val url = java.net.URLDecoder.decode(entry.arguments?.getString("url") ?: "", "UTF-8")
            WebViewScreen(
                viewModel = viewModel,
                smsId = smsId,
                url = url,
                onBack = { navController.popBackStack() }
            )
        }
        composable(
            "pdf/{pdfId}",
            arguments = listOf(navArgument("pdfId") { type = NavType.LongType })
        ) { entry ->
            val pdfId = entry.arguments?.getLong("pdfId") ?: return@composable
            PdfPreviewScreen(
                viewModel = viewModel,
                pdfId = pdfId,
                onBack = { navController.popBackStack() }
            )
        }
    }
}

package com.court.assistant.calendar

import android.content.ContentUris
import android.content.ContentValues
import android.content.Context
import android.provider.CalendarContract
import java.util.*

class CalendarSync(private val context: Context) {

    fun syncHearing(
        caseNumber: String,
        courtName: String?,
        hearingTime: Long,
        defendant: String?,        // 被传唤人
        handler: String?,          // 承办人
        location: String?,         // 应到处所
        phone: String?,            // 电话
        partyNames: String? = null,
        description: String? = null
    ): Long? {
        // 去重：检查是否已存在
        if (eventExists(caseNumber, hearingTime)) return null

        val calendarId = getOrCreateCalendarId() ?: return null
        val title = buildString {
            append("开庭 ")
            if (courtName != null) append("$courtName ")
            append(caseNumber)
        }
        val desc = buildString {
            // 格式化显示精确的开庭时间
            val timeFormat = java.text.SimpleDateFormat("yyyy年MM月dd日 HH:mm", java.util.Locale.CHINA)
            append("⏰ 开庭时间: ${timeFormat.format(java.util.Date(hearingTime))}\n")

            // 7个关键信息字段
            append("案号: $caseNumber")
            if (courtName != null) append("\n法院: $courtName")
            if (defendant != null) append("\n被传唤人: $defendant")
            if (handler != null) append("\n承办人: $handler")
            if (location != null) append("\n应到处所: $location")
            if (phone != null) append("\n电话: $phone")
            if (partyNames != null) append("\n当事人: $partyNames")
            if (description != null) append("\n$description")
        }

        val values = ContentValues().apply {
            put(CalendarContract.Events.CALENDAR_ID, calendarId)
            put(CalendarContract.Events.TITLE, title)
            put(CalendarContract.Events.DESCRIPTION, desc)
            put(CalendarContract.Events.DTSTART, hearingTime)
            put(CalendarContract.Events.DTEND, hearingTime + 2 * 3600 * 1000) // 2小时
            put(CalendarContract.Events.EVENT_TIMEZONE, TimeZone.getDefault().id)
            put(CalendarContract.Events.HAS_ALARM, 1)
        }

        val uri = context.contentResolver.insert(CalendarContract.Events.CONTENT_URI, values)
        val eventId = uri?.let { ContentUris.parseId(it) }

        // 添加提醒：提前1天和1小时
        if (eventId != null) {
            addReminder(eventId, 24 * 60) // 1天
            addReminder(eventId, 60)       // 1小时
        }
        return eventId
    }

    private fun eventExists(caseNumber: String, hearingTime: Long): Boolean {
        val projection = arrayOf(CalendarContract.Events._ID)
        val selection = "${CalendarContract.Events.TITLE} LIKE ? AND ${CalendarContract.Events.DTSTART} = ?"
        val args = arrayOf("%$caseNumber%", hearingTime.toString())
        val cursor = context.contentResolver.query(
            CalendarContract.Events.CONTENT_URI, projection, selection, args, null
        )
        val exists = cursor?.use { it.count > 0 } ?: false
        return exists
    }

    private fun getOrCreateCalendarId(): Long? {
        // 先查找已有日历
        val projection = arrayOf(CalendarContract.Calendars._ID)
        val cursor = context.contentResolver.query(
            CalendarContract.Calendars.CONTENT_URI, projection, null, null, null
        )
        cursor?.use {
            if (it.moveToFirst()) return it.getLong(0)
        }
        return null // 使用系统默认日历
    }

    private fun addReminder(eventId: Long, minutes: Int) {
        val values = ContentValues().apply {
            put(CalendarContract.Reminders.EVENT_ID, eventId)
            put(CalendarContract.Reminders.MINUTES, minutes)
            put(CalendarContract.Reminders.METHOD, CalendarContract.Reminders.METHOD_ALERT)
        }
        context.contentResolver.insert(CalendarContract.Reminders.CONTENT_URI, values)
    }
}

